module.exports = "<ion-button (click)=\"setIsOpened(true)\">عرض سلع</ion-button>\n\n<ion-modal\n  [isOpen]=\"isOpened\"\n  class=\"modal-fullscreen\"\n  (didDismiss)=\"setIsOpened(false)\"\n  #vendorItems\n>\n  <ng-template>\n    <ion-header>\n      <ion-toolbar>\n        <ion-title>سلع الموردين</ion-title>\n        <ion-buttons slot=\"end\">\n          <ion-button (click)=\"setIsOpened(false)\">\n            <ion-icon name=\"close-outline\"></ion-icon>\n          </ion-button>\n        </ion-buttons>\n      </ion-toolbar>\n    </ion-header>\n\n    <ion-content>\n      <div>\n        <ion-card *ngFor=\"let item of selectedItems\" style=\"margin: 10px\">\n          <ion-card-content style=\"padding: 12px\">\n            <ion-grid>\n              <ion-row class=\"ion-align-items-start\" style=\"flex-wrap: wrap\">\n                <ion-col\n                  size=\"12\"\n                  size-md=\"1\"\n                  class=\"ion-text-start\"\n                  style=\"text-align: right; align-self: center\"\n                >\n                  <div class=\"icon-container\">\n                    <div class=\"icon-with-label\">\n                      <ion-icon\n                        size=\"large\"\n                        class=\"add-icon\"\n                        *ngIf=\"item.changeType == 1\"\n                        name=\"add-circle-outline\"\n                      ></ion-icon>\n                      <ion-icon\n                        size=\"large\"\n                        class=\"delete-icon\"\n                        *ngIf=\"item.changeType == 2\"\n                        name=\"remove-circle-outline\"\n                        color=\"danger\"\n                      ></ion-icon>\n                      <ion-icon\n                        size=\"large\"\n                        *ngIf=\"item.changeType == 3\"\n                        name=\"create-outline\"\n                      ></ion-icon>\n\n                      <ion-label\n                        *ngIf=\"item.changeType == 1\"\n                        class=\"icon-label-sm form-label\"\n                        >اضافة {{ getNamingRefValue(\"4\") }}</ion-label\n                      >\n                      <ion-label\n                        *ngIf=\"item.changeType == 3\"\n                        class=\"icon-label-sm form-label\"\n                        >تعديل {{ getNamingRefValue(\"4\") }}</ion-label\n                      >\n                      <ion-label\n                        *ngIf=\"item.changeType == 2\"\n                        class=\"icon-label-sm form-label\"\n                        >حذف {{ getNamingRefValue(\"4\") }}</ion-label\n                      >\n                    </div>\n                  </div>\n                </ion-col>\n\n                <ion-col size=\"12\" size-md=\"11\">\n                  <ion-row>\n                    <ion-col size=\"12\">\n                      <ion-label class=\"form-label\"\n                        >السلعة: {{ item.item_name }}</ion-label\n                      >\n                    </ion-col>\n                  </ion-row>\n                  <ion-row>\n                    <ion-col size=\"12\">\n                      <ion-label class=\"form-label\"\n                        >الفئة: {{ item.cat_name }}</ion-label\n                      >\n                    </ion-col>\n                  </ion-row>\n\n                  <ion-row>\n                    <ion-col\n                      size=\"6\"\n                      size-md=\"3\"\n                      *ngIf=\"item.old_quantity !== item.new_quantity\"\n                    >\n                      <ion-label class=\"form-label\"\n                        ><strong>الكمية من: </strong\n                        >{{ item.old_quantity }}</ion-label\n                      >\n                    </ion-col>\n                    <ion-col\n                      size=\"6\"\n                      size-md=\"3\"\n                      *ngIf=\"item.new_quantity !== item.old_quantity\"\n                    >\n                      <ion-label class=\"form-label\"\n                        ><strong>الكمية إلى: </strong\n                        >{{ item.new_quantity }}</ion-label\n                      >\n                    </ion-col>\n                    <ion-col\n                      size=\"6\"\n                      size-md=\"3\"\n                      *ngIf=\"item.old_item_price !== item.new_item_price\"\n                    >\n                      <ion-label class=\"form-label\"\n                        ><strong>سعر السلعة من: </strong\n                        >{{ item.old_item_price }}</ion-label\n                      >\n                    </ion-col>\n                    <ion-col\n                      size=\"6\"\n                      size-md=\"3\"\n                      *ngIf=\"item.new_item_price !== item.old_item_price\"\n                    >\n                      <ion-label class=\"form-label\"\n                        ><strong>سعر السلعة إلى: </strong\n                        >{{ item.new_item_price }}</ion-label\n                      >\n                    </ion-col>\n                    <ion-col\n                      size=\"6\"\n                      size-md=\"3\"\n                      *ngIf=\"item.old_funded_price !== item.new_funded_price\"\n                    >\n                      <ion-label class=\"form-label\"\n                        ><strong>السعر الممول من: </strong\n                        >{{ item.old_funded_price }}</ion-label\n                      >\n                    </ion-col>\n                    <ion-col\n                      size=\"6\"\n                      size-md=\"3\"\n                      *ngIf=\"item.new_funded_price !== item.old_funded_price\"\n                    >\n                      <ion-label class=\"form-label\"\n                        ><strong>السعر الممول إلى: </strong\n                        >{{ item.new_funded_price }}</ion-label\n                      >\n                    </ion-col>\n                  </ion-row>\n                </ion-col>\n              </ion-row>\n            </ion-grid>\n          </ion-card-content>\n        </ion-card>\n      </div>\n    </ion-content>\n  </ng-template>\n</ion-modal>\n";

