"use strict";
module.exports = "<app-loader [isVisible]=\"showLoader\"></app-loader>\n<div class=\"gallery-wrapper\" id=\"toPrint\" style=\"width: 0%; height: 0px\">\n  <ngx-gallery\n    #ngxGallery\n    [options]=\"galleryOptions\"\n    [images]=\"galleryImages\"\n    class=\"ngx-gallery\"\n    style=\"width: 0%; height: 0px\"\n  >\n  </ngx-gallery>\n</div>\n<ng-container>\n  <ion-accordion-group expand=\"inset\" [multiple]=\"false\" value=\"first\">\n    <ion-accordion value=\"first\">\n      <ion-item slot=\"header\" class=\"text-center\">\n        <ion-label class=\"font-weight-bolder\"\n          ><ion-icon name=\"attach\" size=\"large\" class=\"FormIcon\"></ion-icon>\n          المستندات\n        </ion-label>\n      </ion-item>\n      <div class=\"ion-padding table-responsive\" slot=\"content\">\n        <form [formGroup]=\"documentsObject.formGroup\">\n          <ion-grid fixed=\"true\" style=\"min-width: 1000px\">\n            <ion-row class=\"header-row\">\n              <ion-col size=\"1\">\n                <ion-label>اسم المستند</ion-label>\n              </ion-col>\n              <ion-col size=\"1\">\n                <ion-label>عدد الصفحات المتاحة</ion-label>\n              </ion-col>\n              <ion-col size=\"1\">\n                <ion-label>اجمالي عدد الصفحات</ion-label>\n              </ion-col>\n              <ion-col\n                size=\"1\"\n                [hidden]=\"!inputsInterface.canAddingDocumentsType\"\n              >\n                <app-multiplePopover\n                  [parentForm]=\"documentsObject.formGroup\"\n                  parentFormControllerName=\"documentsType\"\n                  [arrayModal]=\"databaseResponses.allDocumentsTypeInDataBase\"\n                  [arrayName]=\"'documentTypeDesc'\"\n                  [arrayValue]=\"'documentTypeCode'\"\n                  [valuesToDisable]=\"valuesToDisable()\"\n                  [hidden]=\"true\"\n                  [okText]=\"'موافق'\"\n                  [cancelText]=\"'الغاء'\"\n                  placeholderText=\"اختيار نوع المستند\"\n                  (ionDismiss)=\"handleSelectedDocumentTypes()\"\n                ></app-multiplePopover>\n              </ion-col>\n            </ion-row>\n            <ion-row\n              class=\"details-row text-left\"\n              *ngFor=\"let doc of selectedDocuments\"\n            >\n              <ion-col size=\"1\">\n                <ion-label>{{ doc.documentTypeDesc }}</ion-label>\n              </ion-col>\n              <ion-col size=\"1\">\n                <ion-label>{{\n                  getNumberOfPagesExist(doc.documentTypeCode)\n                }}</ion-label>\n              </ion-col>\n              <ion-col size=\"1\">\n                <ion-label> {{ doc.documentPagesNumber }}</ion-label>\n              </ion-col>\n              <ion-col size=\"1\" *ngFor=\"let page of doc.dataForEveryPage\">\n                <ion-button\n                  [disabled]=\"page.base64 == null && !inputsInterface.canEdit\"\n                  (click)=\"clickOnSpecificPage(doc, page.number)\"\n                  color=\"{{ page.base64 === null ? 'danger' : '' }}\"\n                >\n                  {{ page.number }}\n                </ion-button>\n              </ion-col>\n            </ion-row>\n          </ion-grid>\n        </form>\n      </div>\n    </ion-accordion>\n  </ion-accordion-group>\n</ng-container>\n";

